# Now check: what if we vary gf/m² and look for v₀-doubling?
print(f"\n  Scanning gf/m² to find where v₀-doubling might emerge:")

y_values = np.linspace(0.1, 10.0, 200)
for y_val in y_values:
    f_scan = y_val * m_OR**2 / g_OR
    try:
        res = minimize_scalar(lambda x: ORaifeartaigh_CW(x, f_scan, m_OR, g_OR, mu_R)[0],
                              bounds=(0.01, 10.0), method='bounded')
        x_opt = res.x
        _, mb_scan, mf_scan = ORaifeartaigh_CW(x_opt, f_scan, m_OR, g_OR, mu_R)

        # Check for v₀-doubling among mass eigenvalues
        masses_scan = np.sqrt(np.abs(np.sort(np.concatenate([mb_scan, mf_scan]))))
        sqrt_scan = np.sqrt(masses_scan)

        for i in range(len(sqrt_scan)):
            for j in range(i+1, len(sqrt_scan)):
                for k in range(j+1, len(sqrt_scan)):
                    v0s = (sqrt_scan[i] + sqrt_scan[j]) / 3
                    v0f = (-sqrt_scan[i] + sqrt_scan[j] + sqrt_scan[k]) / 3
                    if v0s > 0.001:
                        ratio = v0f / v0s
                        if abs(ratio - 2.0) < 0.05:
                            print(f"    y = {y_val:.3f}, triple ({i},{j},{k}): "
                                  f"ratio = {ratio:.4f}, x_min = {x_opt:.4f}")
    except:
        pass

print(f"\n  (If no output above, no v₀-doubling found in the CW mass spectrum)")
